INSERT INTO question_test_item (id, questionTestId, title, optionA, optionB, optionC, optionD, optionE, answer, analysis, sort, createTime, updateTime, isDelete)
VALUES
    (600011, 5001, '关于“什么是数据库？”，下列说法正确的是？', '数据库是按照一定结构组织、存储和管理数据的集合。', '数据库管理系统是用于建立、管理和维护数据库的软件系统。', '数据库系统通常由数据库、DBMS、应用程序、管理员和用户组成。', '数据模型是对现实世界数据及其关系的抽象描述。', '常见模型有层次模型、网状模型、关系模型和面向对象模型。', 'A', '数据库是按照一定结构组织、存储和管理数据的集合。', 1, NOW(), NOW(), 0),
    (600012, 5001, '下列对“什么是数据库？”的理解，最准确的是哪一项？', '数据库是按照一定结构组织、存储和管理数据的集合。', '数据模型是对现实世界数据及其关系的抽象描述。', '关系数据库以二维表形式组织数据，强调结构化和关系约束。', '三级模式结构包括外模式、模式和内模式，用于实现数据独立性。', 'DBMS 提供统一的数据管理、安全控制、并发控制和恢复机制。', 'A', '数据库是按照一定结构组织、存储和管理数据的集合。', 2, NOW(), NOW(), 0),
